const input = $input.first().json;
const action = input.action || 'generate_image';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const BRIDGE_URL = 'http://file-bridge:3200';
const BFL_BASE = 'https://api.bfl.ai/v1';
const POLL_INTERVAL_MS = 5000;
const POLL_MAX_ATTEMPTS = 5;

const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.bfl-flux&cred_key=eq.bfl_api_key&select=cred_value',
  headers: pgHeaders
});
if (!creds || !creds[0] || !creds[0].cred_value) {
  return [{ json: { error: 'BFL API key not configured. Use add_credential to set bfl-flux / bfl_api_key.' } }];
}
const apiKey = creds[0].cred_value;
const bflHeaders = { 'x-key': apiKey, 'Content-Type': 'application/json' };

async function storeBytesInBridge(bytes, fileName, mimeType) {
  const b64 = Buffer.from(bytes).toString('base64');
  const stored = await helpers.httpRequest({
    method: 'POST',
    url: BRIDGE_URL + '/upload/base64',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ content_base64: b64, file_name: fileName, mime_type: mimeType })
  });
  return stored;
}

async function fetchFileRefAsBase64(fileRef) {
  const meta = await helpers.httpRequest({
    method: 'GET',
    url: BRIDGE_URL + '/files/' + fileRef + '/meta'
  });
  const dl = await helpers.httpRequest({
    method: 'GET',
    url: BRIDGE_URL + '/files/' + fileRef,
    encoding: 'arraybuffer',
    returnFullResponse: true
  });
  const b64 = Buffer.from(dl.body).toString('base64');
  return { base64: b64, mime_type: meta.mime_type || 'image/jpeg', file_name: meta.file_name };
}

function fmtSize(bytes) {
  if (!bytes) return 'unknown size';
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
  return (bytes / 1024 / 1024).toFixed(2) + ' MB';
}

function successFileResult(name, sizeStr, storedId, cost) {
  let msg = 'Image ready: ' + name + ' (' + sizeStr + ')';
  if (cost) msg += ' [cost: ' + Number(cost).toFixed(2) + ' BFL credits]';
  return msg + '\n[send_file: ' + BRIDGE_URL + '/files/' + storedId + ']';
}

async function bflPost(url, body) {
  const resp = await helpers.httpRequest({
    method: 'POST', url, headers: bflHeaders,
    body: JSON.stringify(body),
    returnFullResponse: true, ignoreHttpStatusErrors: true, json: false
  });
  if (resp.statusCode >= 400) {
    const errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
    throw new Error('BFL HTTP ' + resp.statusCode + ': ' + errBody.substring(0, 500));
  }
  return typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
}

async function bflGet(url) {
  const resp = await helpers.httpRequest({
    method: 'GET', url, headers: bflHeaders,
    returnFullResponse: true, ignoreHttpStatusErrors: true, json: false
  });
  if (resp.statusCode >= 400) {
    const errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
    throw new Error('BFL HTTP ' + resp.statusCode + ': ' + errBody.substring(0, 500));
  }
  return typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
}

const MODEL_ENDPOINTS = {
  'flux-2-pro':              'flux-2-pro',
  'flux-2-pro-preview':      'flux-2-pro-preview',
  'flux-2-max':              'flux-2-max',
  'flux-2-flex':             'flux-2-flex',
  'flux-2-klein-9b':         'flux-2-klein-9b',
  'flux-2-klein-9b-preview': 'flux-2-klein-9b-preview',
  'flux-2-klein-4b':         'flux-2-klein-4b'
};

async function pollAndDeliver(pollingUrl, sourceCost) {
  let attempts = 0;
  let result = null;
  while (attempts < POLL_MAX_ATTEMPTS) {
    const r = await bflGet(pollingUrl);
    if (r.status === 'Ready') { result = r; break; }
    if (r.status === 'Error' || r.status === 'Failed') {
      throw new Error('BFL generation failed: ' + JSON.stringify(r).slice(0, 500));
    }
    await new Promise(res => setTimeout(res, POLL_INTERVAL_MS));
    attempts++;
  }
  if (!result) {
    return { result: 'Image still generating. Call wait_for_image AGAIN with the SAME polling_url: ' + pollingUrl };
  }
  const sampleUrl = result.result && result.result.sample;
  if (!sampleUrl) {
    throw new Error('Generation done but no sample URL in result: ' + JSON.stringify(result).slice(0, 300));
  }
  const dl = await helpers.httpRequest({
    method: 'GET', url: sampleUrl, encoding: 'arraybuffer', returnFullResponse: true
  });
  const stored = await storeBytesInBridge(dl.body, 'flux_' + Date.now() + '.jpeg', 'image/jpeg');
  return { result: successFileResult(stored.file_name, fmtSize(stored.size_bytes), stored.id, sourceCost) };
}

if (action === 'generate_image') {
  const prompt = input.prompt;
  if (!prompt) return [{ json: { error: 'Parameter "prompt" is required.' } }];

  const model = input.model || 'flux-2-pro';
  const endpoint = MODEL_ENDPOINTS[model];
  if (!endpoint) {
    return [{ json: { error: 'Unknown model: "' + model + '". Available: ' + Object.keys(MODEL_ENDPOINTS).join(', ') } }];
  }

  const width = parseInt(input.width) || 1024;
  const height = parseInt(input.height) || 1024;
  if (width < 64 || height < 64) {
    return [{ json: { error: 'width and height must each be >= 64. Got ' + width + 'x' + height } }];
  }

  const body = { prompt, width, height };
  if (input.seed) body.seed = parseInt(input.seed);

  if (input.file_ref) {
    try {
      const src = await fetchFileRefAsBase64(input.file_ref);
      body.input_image = src.base64;
    } catch (e) {
      return [{ json: { error: 'Failed to fetch input image from file-bridge: ' + e.message } }];
    }
  } else if (input.image_url) {
    body.input_image = input.image_url;
  }

  try {
    const init = await bflPost(BFL_BASE + '/' + endpoint, body);
    if (!init.polling_url) {
      return [{ json: { error: 'BFL did not return a polling_url. Raw: ' + JSON.stringify(init).slice(0, 500) } }];
    }
    const out = await pollAndDeliver(init.polling_url, init.cost);
    return [{ json: out }];
  } catch (e) {
    return [{ json: { error: 'generate_image failed: ' + e.message } }];
  }

} else if (action === 'wait_for_image') {
  const pollingUrl = input.polling_url;
  if (!pollingUrl) return [{ json: { error: 'Parameter "polling_url" is required.' } }];
  try {
    const out = await pollAndDeliver(pollingUrl, null);
    return [{ json: out }];
  } catch (e) {
    return [{ json: { error: 'wait_for_image failed: ' + e.message } }];
  }

} else if (action === 'get_credits') {
  try {
    const r = await bflGet(BFL_BASE + '/credits');
    const c = (r && typeof r.credits === 'number') ? r.credits.toFixed(2) : JSON.stringify(r);
    return [{ json: { result: 'BFL credit balance: ' + c + ' credits (1 credit = $0.01)' } }];
  } catch (e) {
    return [{ json: { error: 'get_credits failed: ' + e.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: generate_image, wait_for_image, get_credits.' } }];
}
